const webhook = $('Webhook').item.json;
const historyRows = $input.all();

// Format chat history for the prompt
let historyText = '';
if (historyRows && historyRows.length > 0) {
  const messages = historyRows.map(row => {
    const role = row.json.role === 'user' ? 'Klient' : 'Asystent';
    return `${role}: ${row.json.content}`;
  });
  historyText = '\n\nHISTORIA ROZMOWY:\n' + messages.join('\n') + '\n\n';
}

// Current message from user
const currentMessage = webhook.body.message;
const sessionId = webhook.body.sessionId;

return [{
  json: {
    sessionId: sessionId,
    currentMessage: currentMessage,
    historyText: historyText,
    fullPrompt: historyText + 'Klient: ' + currentMessage
  }
}];

